const items = $input.all();
const now = new Date();
const today = now.toLocaleDateString('fr-FR', { timeZone: 'Europe/Paris', day: '2-digit', month: '2-digit', year: 'numeric' });
const todo = items.filter(i => {
  const statut = (i.json.statut || '').trim();
  if (statut !== 'à faire') return false;
  const dp = (i.json.date_prevue || '').trim();
  if (!dp) return true;
  return dp === today;
});
if (!todo.length) return [];
const prio = { 'haute': 0, 'moyenne': 1, 'basse': 2 };
todo.sort((a, b) => (prio[(a.json.priorite || '').toLowerCase()] ?? 3) - (prio[(b.json.priorite || '').toLowerCase()] ?? 3));
return todo;

const item = $('SplitInBatches').item.json;
const instr = '\n\n---\nIMPORTANT : à la toute fin de ta réponse, ajoute exactement une ligne commençant par RAPPORT_JSON: suivie du JSON sur une seule ligne :\nRAPPORT_JSON: {"statut": "succès", "résumé": "description courte", "erreurs": []}\n(statut = succès | partiel | échec)';
let prompt = item.prompt || '';
if (!prompt.includes('RAPPORT_JSON:')) prompt += instr;
const b64 = Buffer.from(prompt).toString('base64');
const tmpFile = '/home/debian/prompts/tmp_' + item.id + '.md';
return [{ json: { ...item, prompt_b64: b64, tmp_file: tmpFile } }];

const rowData = $('Prépare prompt').item.json;
const sshOut = $input.first().json;
const stdout = String(sshOut.stdout || '');
const stderr = String(sshOut.stderr || '');
let statut_final, resume, erreur_msg, telegram_emoji;
let outer = null;
try { outer = JSON.parse(stdout.trim()); } catch(e) {
  const m = stdout.match(/\{[\s\S]+\}$/);
  if (m) { try { outer = JSON.parse(m[0]); } catch(e2) {} }
}
if (!outer) {
  statut_final = 'échec'; erreur_msg = 'Sortie non-JSON: ' + stdout.slice(0,300) + (stderr ? ' | stderr: ' + stderr.slice(0,200) : ''); resume = ''; telegram_emoji = '❌';
} else if (outer.is_error) {
  statut_final = 'échec'; erreur_msg = 'Claude Code error: ' + String(outer.result||'').slice(0,500); resume = ''; telegram_emoji = '❌';
} else {
  const resultText = String(outer.result || '');
  const match = resultText.match(/RAPPORT_JSON:\s*(\{.+\})/);
  if (match) {
    try {
      const inner = JSON.parse(match[1]);
      const s = inner.statut || 'succès';
      statut_final = (s === 'échec') ? 'échec' : 'effectué';
      resume = (inner['résumé'] || inner.resume || resultText.slice(-800)).slice(0, 2000);
      erreur_msg = s === 'échec' ? JSON.stringify(inner.erreurs||[]).slice(0,1000) : '';
      telegram_emoji = s === 'succès' ? '✅' : s === 'partiel' ? '⚠️' : '❌';
    } catch(e) { statut_final = 'effectué'; resume = resultText.slice(-1000); erreur_msg = ''; telegram_emoji = '✅'; }
  } else { statut_final = 'effectué'; resume = resultText.slice(-1000); erreur_msg = ''; telegram_emoji = '✅'; }
}
const telegram_msg = telegram_emoji + ' ' + (rowData.titre||'') + '\n📁 ' + (rowData.repertoire_projet||'') + '\n📝 ' + resume.slice(0,400);
return [{ json: { id: rowData.id, titre: rowData.titre, repertoire_projet: rowData.repertoire_projet, tmp_file: rowData.tmp_file, statut_final, resume: resume.slice(0,2000), erreur_msg: erreur_msg.slice(0,1000), telegram_msg, date_fin: new Date().toLocaleString('fr-FR', { timeZone: 'Europe/Paris', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }) }}];

const item = $input.first().json;
const b64 = item.prompt_b64 || '';
const tf = item.tmp_file || '';
const rp = item.repertoire_projet || '';
const modeleBrut = (item.modele || '').trim().toLowerCase();
const modeleFinal = ['sonnet', 'opus', 'haiku'].includes(modeleBrut) ? modeleBrut : 'sonnet';
const cmd = `export TF='${tf}' RP='${rp}'; mkdir -p /home/debian/prompts && echo '${b64}' | base64 -d > "$TF" && cd "$RP" && timeout 1800 /home/debian/.nvm/versions/node/v22.22.3/bin/claude --dangerously-skip-permissions --model ${modeleFinal} -p "$(cat $TF)" --print --output-format json`;
return [{ json: { ...item, ssh_command: cmd, modele_final: modeleFinal } }];

const raw = $json.claudeResponse || $json.stdout || '';
const match = raw.match(/\{[\s\S]*\}/);
const claudeJson = match ? JSON.parse(match[0]) : null;

if (!claudeJson) {
  return [{ json: { statut: "échec", resume: "Sortie non-JSON: " + raw.slice(0, 200) } }];
}

let resume, statut;

if (claudeJson.is_error) {
  statut = "échec";
  resume = claudeJson.result || "Erreur inconnue";
} else {
  const nestedMatch = (claudeJson.result || '').match(/\{[\s\S]*\}/);
  if (nestedMatch) {
    try {
      const rapport = JSON.parse(nestedMatch[0]);
      statut = rapport.statut === "échec" ? "échec" : "effectué";
      resume = rapport.résumé || rapport.resume || claudeJson.result;
    } catch {
      statut = "effectué";
      resume = claudeJson.result;
    }
  } else {
    statut = "effectué";
    resume = claudeJson.result;
  }
}

return [{ json: { statut, resume } }];
